import time

from django.conf import settings
from django.http import HttpResponseForbidden
from django.utils.deprecation import MiddlewareMixin


class RateLimitMiddleware(MiddlewareMixin):
    """
    Rate limit incoming HTTP requests by IP address.

    When a client exceeds the allowed number of requests within a time window,
    further requests are rejected with a 403 Forbidden response.

    Configuration (Django settings):
        RATE_LIMIT_REQUESTS: Maximum requests per window (default: 100)
        RATE_LIMIT_WINDOW: Time window in seconds (default: 3600)
    """

    def __init__(self, get_response):
        super().__init__(get_response)
        self._request_log = {}
        self._request_count = 0

    def process_request(self, request):
        max_requests = getattr(settings, "RATE_LIMIT_REQUESTS", 100)
        window = getattr(settings, "RATE_LIMIT_WINDOW", 3600)

        self._request_count += 1
        if self._request_count % 100 == 0:
            self._cleanup(window)

        ip = self._get_client_ip(request)
        now = time.time()
        cutoff = now - window

        timestamps = self._request_log.get(ip, [])
        timestamps = [t for t in timestamps if t > cutoff]
        timestamps.append(now)
        self._request_log[ip] = timestamps

        if len(timestamps) > max_requests:
            return HttpResponseForbidden(
                "Rate limit exceeded for IP address %s." % ip
            )

    def _get_client_ip(self, request):
        x_forwarded_for = request.META.get("HTTP_X_FORWARDED_FOR")
        if x_forwarded_for:
            return x_forwarded_for.split(",")[0].strip()
        return request.META.get("REMOTE_ADDR", "")

    def _cleanup(self, window):
        cutoff = time.time() - window
        self._request_log = {
            ip: [t for t in timestamps if t > cutoff]
            for ip, timestamps in self._request_log.items()
            if any(t > cutoff for t in timestamps)
        }

